           ly*lx,ly*ly,ly*lz,-ly*lx,-ly*ly,-ly*lz;
           lz*lx,lz*ly,lz*lz,-lz*lx,-lz*ly,-lz*lz;
           -lx*lx,-lx*ly,-lx*lz,lx*lx,lx*ly,lx*lz;
